import React from 'react';
import { X, ShieldAlert, Activity, Ban, Globe } from 'lucide-react';

const StatDetailsModal = ({ onClose, title, filterId, history }) => {
  const activeThreats = history ? history.filter(t => t.severity === 'CRITICAL') : [];
  const blockedIps = history ? history.map(t => t.source_ip) : [];
  const uniqueCountries = history ? [...new Set(history.map(t => t.origin_country))] : [];

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(11, 15, 25, 0.95)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 }}>
      <div style={{ background: '#0f172a', padding: '30px', borderRadius: '12px', width: '70%', minHeight: '400px', border: '1px solid #475569', boxShadow: '0 0 40px rgba(0,0,0,0.5)' }}>
        
        <div style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid #334155', paddingBottom: '15px', marginBottom: '20px' }}>
          <h2 style={{ margin: 0, color: 'white', display: 'flex', alignItems: 'center', gap: '10px' }}>
            {filterId === 'total' && <ShieldAlert color="#3b82f6" />}
            {filterId === 'active' && <Activity color="#eab308" />}
            {filterId === 'blocked' && <Ban color="#10b981" />}
            {filterId === 'regions' && <Globe color="#8b5cf6" />}
            Analytics: {title}
          </h2>
          <button onClick={onClose} style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: '#ef4444' }}><X size={28} /></button>
        </div>

        {/* DIFFERENT LAYOUTS BASED ON WHICH BLOCK YOU CLICKED */}
        <div style={{ color: '#cbd5e1' }}>
          
          {filterId === 'total' && (
            <div>
              <h3>System Overview</h3>
              <p>Total packets analyzed by CortexShield AI since boot.</p>
              <div style={{ display: 'flex', gap: '20px', marginTop: '20px' }}>
                <div style={{ background: '#1e293b', padding: '20px', borderRadius: '8px', flex: 1 }}>DDoS Mitigated: 45%</div>
                <div style={{ background: '#1e293b', padding: '20px', borderRadius: '8px', flex: 1 }}>Phishing Blocked: 30%</div>
                <div style={{ background: '#1e293b', padding: '20px', borderRadius: '8px', flex: 1 }}>Ransomware Quarantined: 25%</div>
              </div>
            </div>
          )}

          {filterId === 'active' && (
            <div>
              <h3 style={{ color: '#eab308' }}>Live Critical Intrusions ({activeThreats.length})</h3>
              <ul style={{ listStyle: 'none', padding: 0 }}>
                {activeThreats.map((threat, i) => (
                  <li key={i} style={{ background: '#1e293b', margin: '10px 0', padding: '15px', borderRadius: '6px', borderLeft: '4px solid #eab308' }}>
                    <strong>{threat.attack_type}</strong> originating from {threat.origin_country} (IP: {threat.source_ip})
                  </li>
                ))}
              </ul>
            </div>
          )}

          {filterId === 'blocked' && (
            <div>
              <h3 style={{ color: '#10b981' }}>Firewall Blocklist (Auto-Updated)</h3>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                {[...new Set(blockedIps)].map((ip, i) => (
                  <div key={i} style={{ background: '#1e293b', padding: '12px', borderRadius: '6px', fontFamily: 'monospace', color: '#10b981' }}>
                    <Ban size={14} style={{ marginRight: '8px' }} /> {ip} - STATUS: BLOCKED
                  </div>
                ))}
              </div>
            </div>
          )}

          {filterId === 'regions' && (
            <div>
              <h3 style={{ color: '#8b5cf6' }}>Geographic Threat Distribution</h3>
              <ul style={{ listStyle: 'none', padding: 0 }}>
                {uniqueCountries.map((country, i) => (
                  <li key={i} style={{ background: '#1e293b', margin: '10px 0', padding: '15px', borderRadius: '6px', display: 'flex', justifyContent: 'space-between' }}>
                    <span>{country}</span>
                    <span style={{ color: '#8b5cf6', fontWeight: 'bold' }}>Active Threat Actor</span>
                  </li>
                ))}
              </ul>
            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default StatDetailsModal;
